import React from 'react'
import { Navbar, Nav, NavItem, NavDropdown, MenuItem } from 'react-bootstrap';
import { LinkContainer } from "react-router-bootstrap";
import Link from 'gatsby-link'
import Project from '../components/project'
import Career from '../components/career'
import About from '../components/about'
const MyHeader = () => (
  <Navbar inverse collapseOnSelect fluid>
    <Navbar.Header>
      <Navbar.Brand>
        <a href="/">
        Neel Patel
        </a>
      </Navbar.Brand>
      <Navbar.Toggle />
    </Navbar.Header>
    <Navbar.Collapse>
      <Nav>
        <NavDropdown eventKey={3} title="Contact Me!" id="basic-nav-dropdown">
          <MenuItem eventKey={3.1} href="https://github.com/neelpatel14">Github</MenuItem>
          <MenuItem eventKey={3.2} href="https://www.linkedin.com/in/npatel14">LinkedIn</MenuItem>
          <MenuItem divider />
          <MenuItem eventKey={3.3}href="mailto:patel.neel4550@gmail.com?Subject=Work%20Offer">Email</MenuItem>
        </NavDropdown>
      </Nav>
      <Nav pullRight>
        <LinkContainer to="/about" style={{color:"white"}}>
          <NavItem eventKey={1}>
          <div className="mytooltip">
          <About />
          <span className="mytooltiptext">About Me</span>
          </div>
          </NavItem>
        </LinkContainer>
        <LinkContainer to="/projects" style={{color:"white"}}>

          <NavItem eventKey={2}>
          <div className="mytooltip">
          <Project />
          <span className="mytooltiptext">Projects</span>
          </div>
          </NavItem>
        </LinkContainer>
        <LinkContainer to="/career" style={{color:"white"}}>
          <NavItem eventKey={3}>
            <div className="mytooltip">
            <Career />
            <span className="mytooltiptext">My Career</span>
            </div>
          </NavItem>
        </LinkContainer>
      </Nav>
    </Navbar.Collapse>
  </Navbar>
)

export default MyHeader;



